class Solution {
public:
    int lengthOfLastWord(string s) {
        int n = s.size();

        bool char_seen = false;
        int last_space = n;
        for(int i =n-1; i > 0; i--){
            if(s[i] == ' '){
                if (char_seen)
                    return last_space - i -1;
                last_space = i;
            }
            else{
                char_seen = true;
            }

        }


        return n;

    }
};

class Solution {
public:
    int lengthOfLastWord(string s) {
        int n = s.size();

        int chars = 0;
        for(int i =n-1; i > 0; i--){
            if(s[i] == ' '){
                if (chars)
                    return chars;
            }
            else{
                chars++;
            }

        }


        return chars;

    }
};

class Solution {
public:
    int lengthOfLastWord(string s) {
        int n = s.size();

        int chars = 0;
        for(int i =n-1; i >= 0; i--){
            if(s[i] == ' '){
                if (chars)
                    return chars;
            }
            else{
                chars++;
            }

        }


        return chars;

    }
};
